const GlobalTrending: React.FC<GlobalTrendingProps> = ({ onSelectArticle }) => {
  const [trendingArticles, setTrendingArticles] = useState<Article[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  useEffect(() => {
    getTrendingArticles().then(articles => {
      setTrendingArticles(articles);
      setIsLoading(false);
    });
  }, []);

  return (
    <div className="w-full max-w-7xl mx-auto px-4 stagger-fade-in-up-trigger">
      <div className="text-center mb-16">
        <h2 className="text-3xl md:text-4xl lg:text-5xl font-black text-white mb-6 uppercase tracking-tight">
          GLOBAL <span className="text-[#e62e2e]">TRENDING</span>
        </h2>
        <p className="text-gray-300 max-w-3xl mx-auto text-sm sm:text-base leading-relaxed font-medium tracking-wide">
          AI-powered summaries of pressing geopolitical and economic topics, refreshed twice daily for critical insight.
        </p>
      </div>

      {isLoading ? (
        <div className="flex justify-center items-center py-24">
          <div className="w-10 h-10 border-4 border-cyan-500 border-t-transparent rounded-full animate-spin"></div>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 stagger-fade-in-up">
          {trendingArticles.map((article, idx) => (
            <TrendingCard
              key={article.id}
              article={article}
              index={idx}
              onClick={() => onSelectArticle(article)}
            />
          ))}
        </div>
      )}
    </div>
  );
};

export default GlobalTrending;

