/**
 * AI-Powered Trending Engine
 * Uses Gemini with Google Search to fetch real-time news as of today.
 */
export const getTrendingArticles = async (): Promise<Article[]> => {
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // System prompt instructs the model to act as a research engine
        // focusing specifically on geopolitical/economic news updated by 7 AM.
        const prompt = `Identify and summarize the 3 most significant global geopolitical or economic news stories from today. 
        Focus on events that are trending as of 7:00 AM UTC today.
        Return the response in a structured JSON format that matches the following schema:
        Array of objects with: title (catchy headline), excerpt (150-200 chars), content (full 2-paragraph summary), category (must be 'Economic Insights', 'Political Commentary', or 'Social Responsibility'), readTime (integer).`;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            title: { type: Type.STRING },
                            excerpt: { type: Type.STRING },
                            content: { type: Type.STRING },
                            category: { type: Type.STRING },
                            readTime: { type: Type.INTEGER }
                        },
                        required: ["title", "excerpt", "content", "category", "readTime"]
                    }
                }
            },
        });

        const trendingData = JSON.parse(response.text || '[]');

        // Map AI results to our Article type
        return trendingData.map((data: any, index: number) => ({
            id: 1000 + index,
            title: data.title,
            excerpt: data.excerpt,
            content: data.content,
            // Use relevant Unsplash images based on category
            imageUrl: data.category === 'Economic Insights' 
                ? 'https://images.unsplash.com/photo-1611974714013-3c8c0d088bd3?q=80&w=2000&auto=format&fit=crop'
                : data.category === 'Political Commentary'
                ? 'https://images.unsplash.com/photo-1529107386315-e1a2ed48a620?q=80&w=2000&auto=format&fit=crop'
                : 'https://images.unsplash.com/photo-1509099836639-18ba1795216d?q=80&w=2000&auto=format&fit=crop',
            category: data.category,
            author: marcioNovus,
            date: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
            readTime: data.readTime,
            tags: ['AI-POWERED', 'LIVE-ANALYSIS'],
            groundingLinks: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => chunk.web?.uri).filter(Boolean) || []
        }));

    } catch (error) {
        console.error("AI Trending Error:", error);
        // Fallback to static data if AI fails
        return [
            {
                id: 101,
                title: 'Geopolitical Tensions and Supply Chain...',
                excerpt: 'Ongoing conflicts continue to disrupt global trade routes, energy markets, and critical supply chains as of 7 AM today.',
                content: 'Full analysis of geopolitical tensions and their impact on global supply chains.',
                imageUrl: 'https://images.unsplash.com/photo-1526778548025-fa2f459cd5c1?q=80&w=2000&auto=format&fit=crop',
                category: 'Economic Insights',
                author: marcioNovus,
                date: 'Oct 28, 2023',
                readTime: 8,
                tags: ['Geopolitics', 'Economy']
            },
            // ... more fallbacks could go here
        ];
    }
};

