const GlobalTrending: React.FC<GlobalTrendingProps> = ({ onSelectArticle }) => {
  const [trendingArticles, setTrendingArticles] = useState<Article[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  useEffect(() => {
    // Calculate the most recent 7:00 AM timestamp
    const now = new Date();
    const today7AM = new Date();
    today7AM.setHours(7, 0, 0, 0);

    let updateTime: Date;
    if (now >= today7AM) {
        updateTime = today7AM;
    } else {
        const yesterday7AM = new Date();
        yesterday7AM.setDate(yesterday7AM.getDate() - 1);
        yesterday7AM.setHours(7, 0, 0, 0);
        updateTime = yesterday7AM;
    }

    setLastUpdated(updateTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) + ' Today');

    getTrendingArticles().then(articles => {
      setTrendingArticles(articles);
      setIsLoading(false);
    });
  }, []);

  return (
    <div className="w-full max-w-7xl mx-auto px-4 stagger-fade-in-up-trigger">
      <div className="text-center mb-16">
        <div className="inline-flex items-center gap-3 bg-[#e62e2e]/10 border border-[#e62e2e]/20 px-4 py-1.5 rounded-full mb-8">
